  app.post("/api/invoices", checkPermission("billing_invoices"), async (req, res) => {
    try {
      const data = insertInvoiceSchema.parse(req.body);
      const invoice = await storage.createInvoice(data);

      const flywheelSyncResults: any[] = [];
      if (invoice.outcomeId) {
        const outcomeIds = [invoice.outcomeId];
        for (const oid of outcomeIds) {
          try {
            const outcome = await storage.getOutcome(oid);
            if (!outcome) continue;

            const allEvents = await storage.getOutcomeEventsByOutcome(oid);
            const cutoffDate = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
            const recentEvents = allEvents.filter(e => e.createdAt && new Date(e.createdAt) >= cutoffDate);

            const rejectedEvents = recentEvents.filter(e => !e.billable && e.excludeReason);
            const acceptedEvents = recentEvents
              .filter(e => e.billable === true)
              .sort((a, b) => {
                const aTime = a.createdAt ? new Date(a.createdAt).getTime() : 0;
                const bTime = b.createdAt ? new Date(b.createdAt).getTime() : 0;
                return bTime - aTime;
              })
              .slice(0, 20);

            const agents = (await storage.getAgents()).filter(a => a.outcomeId === oid);
            if (agents.length === 0) continue;

            const primaryAgent = agents[0];
            const existingSuites = await storage.getEvalsByAgent(primaryAgent.id);
            let kpiSuite = existingSuites.find(s => s.type === "kpi_aligned");
            if (!kpiSuite) {
              const generated = await generateKpiAlignedEvalSuite(primaryAgent.id, oid);
              if (generated) {
                kpiSuite = generated.suite;
              } else {
                kpiSuite = await storage.createEvalSuite({
                  agentId: primaryAgent.id,
                  name: `${primaryAgent.name} - Production Feedback Suite (${outcome.name})`,
                  type: "kpi_aligned",
                  totalCases: 0,
                  coverageTags: ["production_feedback", "ground_truth"],
                  ontologyTags: { kpiAligned: true, outcomeId: oid, outcomeName: outcome.name, generatedAt: new Date().toISOString() },
                });
              }
            }

            const suiteId = kpiSuite!.id;
            const existingCases = await storage.getEvalTestCases(suiteId);
            const existingOriginIds = new Set(
              existingCases
                .filter(tc => tc.origin === "production_feedback")
                .map(tc => {
                  const input = tc.inputData as Record<string, unknown> | null;
                  return input?.sourceEventId || input?.sourceDisputeId;
                })
                .filter(Boolean)
            );

            let created = 0;

            for (const ev of rejectedEvents) {
              if (existingOriginIds.has(ev.id)) continue;
              await storage.createEvalTestCase({
                suiteId,
                name: `Production Rejection: ${ev.excludeReason || "excluded"} (${ev.type})`,
                inputData: {
                  type: "production_feedback",
                  sourceEventId: ev.id,
                  traceId: ev.traceId,
                  agentId: ev.agentId,
                  eventType: ev.type,
                  payload: ev.payload,
                  scenario: "rejected_outcome_event",
                  groundTruthLabel: "negative",
                  autoSynced: true,
                  trigger: "invoice_creation",
                },
                expectedOutput: {
                  shouldPass: false,
                  rejectionReason: ev.excludeReason,
                  expectedBehavior: `Agent output was rejected: ${ev.excludeReason}. Future runs must not reproduce this failure pattern.`,
                },
                tags: ["production_feedback", "ground_truth", "rejected_event", "auto_synced", ev.excludeReason || "excluded"],
                weight: 1.5,
                origin: "production_feedback",
                severity: "high",
              });
              created++;
            }

            for (const ev of acceptedEvents) {
              if (existingOriginIds.has(ev.id)) continue;
              await storage.createEvalTestCase({
                suiteId,
                name: `Production Accepted: ${ev.type} (billable)`,
                inputData: {
                  type: "production_feedback",
                  sourceEventId: ev.id,
                  traceId: ev.traceId,
                  agentId: ev.agentId,
                  eventType: ev.type,
                  payload: ev.payload,
                  scenario: "accepted_outcome_event",
                  groundTruthLabel: "positive",
                  autoSynced: true,
                  trigger: "invoice_creation",
                },
                expectedOutput: {
                  shouldPass: true,
                  expectedBehavior: `Agent output was accepted and billed successfully. This represents correct agent behavior for event type: ${ev.type}.`,
                },
                tags: ["production_feedback", "ground_truth", "accepted_event", "auto_synced"],
                weight: 1.0,
                origin: "production_feedback",
                severity: "low",
              });
              created++;
            }

            if (created > 0) {
              const currentCases = await storage.getEvalTestCases(suiteId);
              await storage.updateEvalSuite(suiteId, { totalCases: currentCases.length });
            }

            flywheelSyncResults.push({ outcomeId: oid, suiteId, casesCreated: created });

            await storage.createAuditEvent({
              actorType: "system",
              action: "flywheel_auto_sync",
              objectType: "eval_suite",
              objectId: suiteId,
              details: `Auto-synced ${created} production feedback cases for outcome ${outcome.name} triggered by invoice creation (invoice ${invoice.id})`,
            });
          } catch (syncErr: any) {
            flywheelSyncResults.push({ outcomeId: oid, error: syncErr.message });
          }
        }
      }

      res.status(201).json({ ...invoice, flywheelSync: flywheelSyncResults });
    } catch (e) {
      handleZodError(res, e);
    }
  });

  app.get("/api/invoices/:id", async (req, res) => {
    const invoice = await storage.getInvoice(req.params.id);
    if (!invoice) return res.status(404).json({ error: "Invoice not found" });
    res.json(invoice);
  });

  app.get("/api/invoices/:id/line-items", async (req, res) => {
    const invoice = await storage.getInvoice(req.params.id);
    if (!invoice) return res.status(404).json({ error: "Invoice not found" });
    const events = await storage.getOutcomeEventsByInvoice(req.params.id);
    const traces = await storage.getTraces();
    const agents = await storage.getAgents();
    const lineItems = events.map(event => {
      const trace = event.traceId ? traces.find(t => t.id === event.traceId) : null;
      const agent = event.agentId ? agents.find(a => a.id === event.agentId) : null;
      return {
        ...event,
        agentName: agent?.name || null,
        traceStatus: trace?.status || null,
        traceLatencyMs: trace?.latencyMs || null,
      };
    });
    res.json({ invoice, lineItems });
  });

  app.get("/api/billing/metering-dashboard", async (_req, res) => {
    try {
      const allInvoices = await storage.getInvoices();
      const allEvents = await storage.getOutcomeEvents();
      const allDisputes = await storage.getBillingDisputes();
      const outcomes = await storage.getOutcomes();
      const allAgents = await storage.getAgents();
      const allTraces = await storage.getTraces();
      const agentOutcomeMap = new Map(allAgents.map(a => [a.id, a.outcomeId]));
      const INFRA_OVERHEAD_RATE = 0.15;
      const TOOL_CALL_COST_RATE = 0.001;

      const totalEvents = allEvents.length;
      const billableEvents = allEvents.filter(e => e.billable);
      const excludedEvents = allEvents.filter(e => !e.billable);
      const acceptanceRate = totalEvents > 0 ? billableEvents.length / totalEvents : 0;

      const totalUnitsDelivered = allEvents.reduce((sum, e) => sum + (e.unitCount || 1), 0);
      const billableUnits = billableEvents.reduce((sum, e) => sum + (e.unitCount || 1), 0);
      const excludedUnits = excludedEvents.reduce((sum, e) => sum + (e.unitCount || 1), 0);

      const paidInvoices = allInvoices.filter(inv => inv.status === "paid");
      const pendingInvoices = allInvoices.filter(inv => inv.status === "pending");
      const totalRevenue = paidInvoices.reduce((sum, inv) => sum + (inv.amount || 0), 0);
      const pendingRevenue = pendingInvoices.reduce((sum, inv) => sum + (inv.amount || 0), 0);

      const now = new Date();
      const monthlyRevenue: Array<{ month: string; revenue: number; units: number }> = [];
      for (let m = 5; m >= 0; m--) {
        const d = new Date(now.getFullYear(), now.getMonth() - m, 1);
        const monthKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
        const monthInvoices = allInvoices.filter(inv => {
          if (!inv.periodStart) return false;
          const ps = new Date(inv.periodStart);
          return ps.getFullYear() === d.getFullYear() && ps.getMonth() === d.getMonth();
        });
        monthlyRevenue.push({
          month: monthKey,
          revenue: monthInvoices.reduce((s, inv) => s + (inv.amount || 0), 0),
          units: monthInvoices.reduce((s, inv) => s + (inv.totalUnits || 0), 0),
        });
      }

      const revenueGrowth = monthlyRevenue.length >= 2 && monthlyRevenue[monthlyRevenue.length - 2].revenue > 0
        ? ((monthlyRevenue[monthlyRevenue.length - 1].revenue - monthlyRevenue[monthlyRevenue.length - 2].revenue) / monthlyRevenue[monthlyRevenue.length - 2].revenue * 100)
        : 0;

      const avgMonthlyRevenue = monthlyRevenue.reduce((s, m) => s + m.revenue, 0) / Math.max(monthlyRevenue.filter(m => m.revenue > 0).length, 1);
      const projectedAnnualRevenue = avgMonthlyRevenue * 12;

      const excludeReasons: Record<string, number> = {};
      excludedEvents.forEach(e => {
        const reason = e.excludeReason || "unspecified";
        excludeReasons[reason] = (excludeReasons[reason] || 0) + 1;
      });

      const outcomeCostLookup: Record<string, { llm: number; tool: number }> = {};
      for (const trace of allTraces) {
        const oId = agentOutcomeMap.get(trace.agentId);
        if (!oId) continue;
        if (!outcomeCostLookup[oId]) outcomeCostLookup[oId] = { llm: 0, tool: 0 };
        outcomeCostLookup[oId].llm += trace.costUsd || 0;
        const tc = trace.toolCalls as any[] | null;
        outcomeCostLookup[oId].tool += (Array.isArray(tc) ? tc.length : 0) * TOOL_CALL_COST_RATE;
      }

      const outcomeMetering = outcomes.map(o => {
        const oEvents = allEvents.filter(e => e.outcomeId === o.id);
        const oInvoices = allInvoices.filter(inv => inv.outcomeId === o.id);
        const oDisputes = allDisputes.filter(d => d.outcomeId === o.id);
        const oBillable = oEvents.filter(e => e.billable);
        const totalRevenue = oInvoices.reduce((s, inv) => s + (inv.amount || 0), 0);
        const costs = outcomeCostLookup[o.id];
        const directCost = costs ? costs.llm + costs.tool : 0;
        const costToServe = Math.round(directCost * (1 + INFRA_OVERHEAD_RATE) * 100) / 100;
        const margin = Math.round((totalRevenue - costToServe) * 100) / 100;
        const marginPercent = totalRevenue > 0 ? Math.round(((totalRevenue - costToServe) / totalRevenue) * 1000) / 10 : 0;
        return {
          outcomeId: o.id,
          outcomeName: o.name,
          totalEvents: oEvents.length,
          billableEvents: oBillable.length,
          excludedEvents: oEvents.length - oBillable.length,
          acceptanceRate: oEvents.length > 0 ? oBillable.length / oEvents.length : 0,
          totalRevenue,
          totalUnits: oEvents.reduce((s, e) => s + (e.unitCount || 1), 0),
          invoiceCount: oInvoices.length,
          disputeCount: oDisputes.length,
          disputeAmount: oDisputes.reduce((s, d) => s + (d.amount || 0), 0),
          costToServe,
          margin,
          marginPercent,
        };
      });

      const openDisputes = allDisputes.filter(d => d.status === "open");
      const resolvedDisputes = allDisputes.filter(d => d.status === "resolved");
      const rejectedDisputes = allDisputes.filter(d => d.status === "rejected");
      const disputeCategories: Record<string, number> = {};
      allDisputes.forEach(d => {
        disputeCategories[d.category] = (disputeCategories[d.category] || 0) + 1;
      });

      const totalCostToServe = outcomeMetering.reduce((s, o) => s + o.costToServe, 0);
      const totalMargin = totalRevenue - totalCostToServe;
      const totalMarginPercent = totalRevenue > 0 ? Math.round(((totalRevenue - totalCostToServe) / totalRevenue) * 1000) / 10 : 0;

      const monthlyMargin = monthlyRevenue.map(mr => {
        const monthTraces = allTraces.filter(t => {
          if (!t.startedAt) return false;
          const d = new Date(t.startedAt);
          const mk = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
          return mk === mr.month;
        });
        let mCost = 0;
        for (const t of monthTraces) {
          const llm = t.costUsd || 0;
          const tc = t.toolCalls as any[] | null;
          const tool = (Array.isArray(tc) ? tc.length : 0) * TOOL_CALL_COST_RATE;
          mCost += (llm + tool) * (1 + INFRA_OVERHEAD_RATE);
        }
        const mMargin = mr.revenue - Math.round(mCost * 100) / 100;
        return { month: mr.month, revenue: mr.revenue, cost: Math.round(mCost * 100) / 100, margin: Math.round(mMargin * 100) / 100 };
      });

      res.json({
        summary: {
          totalRevenue,
          pendingRevenue,
          projectedAnnualRevenue,
          revenueGrowth: Math.round(revenueGrowth * 10) / 10,
          totalUnitsDelivered,
          billableUnits,
          excludedUnits,
          acceptanceRate: Math.round(acceptanceRate * 1000) / 10,
          totalInvoices: allInvoices.length,
          paidInvoices: paidInvoices.length,
          pendingInvoices: pendingInvoices.length,
          totalCostToServe: Math.round(totalCostToServe * 100) / 100,
          totalMargin: Math.round(totalMargin * 100) / 100,
          totalMarginPercent,
        },
        monthlyRevenue,
        monthlyMargin,
        excludeReasons,
        outcomeMetering,
        disputes: {
          total: allDisputes.length,
          open: openDisputes.length,
          resolved: resolvedDisputes.length,
          rejected: rejectedDisputes.length,
          totalAmount: allDisputes.reduce((s, d) => s + (d.amount || 0), 0),
          categories: disputeCategories,
        },
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message || "Failed to compute metering dashboard" });
    }
  });

  app.get("/api/billing/cost-attribution", async (req, res) => {
    try {
      const period = (req.query.period as string) || "90d";
      const now = new Date();
      let cutoff: Date | null = null;
      if (period === "30d") cutoff = new Date(now.getTime() - 30 * 86400000);
      else if (period === "90d") cutoff = new Date(now.getTime() - 90 * 86400000);

      const allTraces = await storage.getTraces();
      const filteredTraces = cutoff
        ? allTraces.filter(t => t.startedAt && new Date(t.startedAt) >= cutoff!)
        : allTraces;

      const agents = await storage.getAgents();
      const outcomes = await storage.getOutcomes();
      const agentMap = new Map(agents.map(a => [a.id, a]));
      const outcomeMap = new Map(outcomes.map(o => [o.id, o]));

      const INFRA_OVERHEAD_RATE = 0.15;
      const TOOL_CALL_COST = 0.001;

      const agentCosts: Record<string, {
        agentId: string; agentName: string; outcomeId: string | null; outcomeName: string | null;
        llmCost: number; toolCost: number; toolCallCount: number; traceCount: number; totalTokens: number;
        monthlyCosts: Record<string, { llm: number; tool: number; infra: number; traces: number }>;
      }> = {};

      for (const trace of filteredTraces) {
        const agentId = trace.agentId;
        if (!agentCosts[agentId]) {
          const agent = agentMap.get(agentId);
          agentCosts[agentId] = {
            agentId,
            agentName: agent?.name || "Unknown Agent",
            outcomeId: agent?.outcomeId || null,
            outcomeName: agent?.outcomeId ? outcomeMap.get(agent.outcomeId)?.name || null : null,
            llmCost: 0, toolCost: 0, toolCallCount: 0, traceCount: 0, totalTokens: 0,
            monthlyCosts: {},
          };
        }

        const entry = agentCosts[agentId];
        entry.traceCount++;
        entry.llmCost += trace.costUsd || 0;

        const tokenUsage = trace.tokenUsage as { prompt_tokens?: number; completion_tokens?: number; total_tokens?: number } | null;
        if (tokenUsage) {
          entry.totalTokens += tokenUsage.total_tokens || 0;
        }

        const toolCalls = trace.toolCalls as any[] | null;
        const toolCallCount = Array.isArray(toolCalls) ? toolCalls.length : 0;
        entry.toolCallCount += toolCallCount;
        entry.toolCost += toolCallCount * TOOL_CALL_COST;

        if (trace.startedAt) {
          const d = new Date(trace.startedAt);
          const monthKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
          if (!entry.monthlyCosts[monthKey]) {
            entry.monthlyCosts[monthKey] = { llm: 0, tool: 0, infra: 0, traces: 0 };
          }
          entry.monthlyCosts[monthKey].llm += trace.costUsd || 0;
          entry.monthlyCosts[monthKey].tool += toolCallCount * TOOL_CALL_COST;
          entry.monthlyCosts[monthKey].traces++;
        }
      }

      for (const entry of Object.values(agentCosts)) {
        for (const mc of Object.values(entry.monthlyCosts)) {
          mc.infra = (mc.llm + mc.tool) * INFRA_OVERHEAD_RATE;
        }
      }

      const outcomeCosts: Record<string, {
        outcomeId: string; outcomeName: string;
        totalCost: number; llmCost: number; toolCost: number; infraCost: number;
        traceCount: number; toolCallCount: number; totalTokens: number;
        avgCostPerTrace: number;
        agents: Array<{ agentId: string; agentName: string; llmCost: number; toolCost: number; infraCost: number; totalCost: number; traceCount: number }>;
        costTrend: Array<{ month: string; llm: number; tool: number; infra: number; total: number }>;
      }> = {};

      const UNATTRIBUTED = "__unattributed__";

      for (const entry of Object.values(agentCosts)) {
        const oId = entry.outcomeId || UNATTRIBUTED;
        if (!outcomeCosts[oId]) {
          outcomeCosts[oId] = {
            outcomeId: oId,
            outcomeName: entry.outcomeName || "Unattributed",
            totalCost: 0, llmCost: 0, toolCost: 0, infraCost: 0,
            traceCount: 0, toolCallCount: 0, totalTokens: 0, avgCostPerTrace: 0,
            agents: [], costTrend: [],
          };
        }

        const oc = outcomeCosts[oId];
        const directCost = entry.llmCost + entry.toolCost;
        const infraCost = directCost * INFRA_OVERHEAD_RATE;
        const totalCost = directCost + infraCost;

        oc.llmCost += entry.llmCost;
        oc.toolCost += entry.toolCost;
        oc.infraCost += infraCost;
        oc.totalCost += totalCost;
        oc.traceCount += entry.traceCount;
        oc.toolCallCount += entry.toolCallCount;
        oc.totalTokens += entry.totalTokens;

        oc.agents.push({
          agentId: entry.agentId,
          agentName: entry.agentName,
          llmCost: Math.round(entry.llmCost * 10000) / 10000,
          toolCost: Math.round(entry.toolCost * 10000) / 10000,
          infraCost: Math.round((entry.llmCost + entry.toolCost) * INFRA_OVERHEAD_RATE * 10000) / 10000,
          totalCost: Math.round((entry.llmCost + entry.toolCost) * (1 + INFRA_OVERHEAD_RATE) * 10000) / 10000,
          traceCount: entry.traceCount,
        });
      }

      const allMonths = new Set<string>();
      for (const entry of Object.values(agentCosts)) {
        for (const mk of Object.keys(entry.monthlyCosts)) allMonths.add(mk);
      }
      const sortedMonths = Array.from(allMonths).sort();

      for (const oc of Object.values(outcomeCosts)) {
        oc.avgCostPerTrace = oc.traceCount > 0 ? Math.round((oc.totalCost / oc.traceCount) * 10000) / 10000 : 0;
        oc.totalCost = Math.round(oc.totalCost * 100) / 100;
        oc.llmCost = Math.round(oc.llmCost * 100) / 100;
        oc.toolCost = Math.round(oc.toolCost * 100) / 100;
        oc.infraCost = Math.round(oc.infraCost * 100) / 100;

        const agentIds = oc.agents.map(a => a.agentId);
        oc.costTrend = sortedMonths.map(month => {
          let llm = 0, tool = 0, infra = 0;
          for (const aid of agentIds) {
            const mc = agentCosts[aid]?.monthlyCosts[month];
            if (mc) { llm += mc.llm; tool += mc.tool; infra += mc.infra; }
          }
          return {
            month,
            llm: Math.round(llm * 100) / 100,
            tool: Math.round(tool * 100) / 100,
            infra: Math.round(infra * 100) / 100,
            total: Math.round((llm + tool + infra) * 100) / 100,
          };
        });
      }

      const outcomeList = Object.values(outcomeCosts).filter(o => o.outcomeId !== UNATTRIBUTED);
      const unattributed = outcomeCosts[UNATTRIBUTED] || null;

      const totalCost = outcomeList.reduce((s, o) => s + o.totalCost, 0) + (unattributed?.totalCost || 0);
      const totalLlmCost = outcomeList.reduce((s, o) => s + o.llmCost, 0) + (unattributed?.llmCost || 0);
      const totalToolCost = outcomeList.reduce((s, o) => s + o.toolCost, 0) + (unattributed?.toolCost || 0);
      const totalInfraCost = outcomeList.reduce((s, o) => s + o.infraCost, 0) + (unattributed?.infraCost || 0);

      res.json({
        summary: {
          totalCost: Math.round(totalCost * 100) / 100,
          llmCost: Math.round(totalLlmCost * 100) / 100,
          toolCost: Math.round(totalToolCost * 100) / 100,
          infraCost: Math.round(totalInfraCost * 100) / 100,
          totalTraces: filteredTraces.length,
          avgCostPerTrace: filteredTraces.length > 0 ? Math.round((totalCost / filteredTraces.length) * 10000) / 10000 : 0,
          infraOverheadRate: INFRA_OVERHEAD_RATE,
          toolCallCostRate: TOOL_CALL_COST,
          period,
        },
        outcomes: outcomeList,
        unattributed,
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message || "Failed to compute cost attribution" });
    }
  });

  app.get("/api/billing/margin-analysis", async (req, res) => {
    try {
      const period = (req.query.period as string) || "90d";
      const now = new Date();
      let cutoff: Date | null = null;
      if (period === "30d") cutoff = new Date(now.getTime() - 30 * 86400000);
      else if (period === "90d") cutoff = new Date(now.getTime() - 90 * 86400000);

      const allTraces = await storage.getTraces();
      const filteredTraces = cutoff
        ? allTraces.filter(t => t.startedAt && new Date(t.startedAt) >= cutoff!)
        : allTraces;

      const agents = await storage.getAgents();
      const outcomes = await storage.getOutcomes();
      const allInvoices = await storage.getInvoices();
      const allEvents = await storage.getOutcomeEvents();
      const agentMap = new Map(agents.map(a => [a.id, a]));
      const outcomeMap = new Map(outcomes.map(o => [o.id, o]));

      const INFRA_OVERHEAD_RATE = 0.15;
      const TOOL_CALL_COST = 0.001;

      const outcomeCostMap: Record<string, { llm: number; tool: number; traceCount: number; monthly: Record<string, { llm: number; tool: number }> }> = {};

      for (const trace of filteredTraces) {
        const agent = agentMap.get(trace.agentId);
        const oId = agent?.outcomeId;
        if (!oId) continue;

        if (!outcomeCostMap[oId]) {
          outcomeCostMap[oId] = { llm: 0, tool: 0, traceCount: 0, monthly: {} };
        }
        const entry = outcomeCostMap[oId];
        entry.llm += trace.costUsd || 0;
        const toolCalls = trace.toolCalls as any[] | null;
        entry.tool += (Array.isArray(toolCalls) ? toolCalls.length : 0) * TOOL_CALL_COST;
        entry.traceCount++;

        if (trace.startedAt) {
          const d = new Date(trace.startedAt);
          const mk = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
          if (!entry.monthly[mk]) entry.monthly[mk] = { llm: 0, tool: 0 };
          entry.monthly[mk].llm += trace.costUsd || 0;
          entry.monthly[mk].tool += (Array.isArray(toolCalls) ? toolCalls.length : 0) * TOOL_CALL_COST;
        }
      }

      const outcomeRevenueMap: Record<string, { total: number; monthly: Record<string, number> }> = {};
      for (const inv of allInvoices) {
        const oId = inv.outcomeId;
        if (!oId) continue;
        if (!outcomeRevenueMap[oId]) outcomeRevenueMap[oId] = { total: 0, monthly: {} };
        outcomeRevenueMap[oId].total += inv.amount || 0;
        if (inv.periodStart) {
          const d = new Date(inv.periodStart);
          const mk = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
          outcomeRevenueMap[oId].monthly[mk] = (outcomeRevenueMap[oId].monthly[mk] || 0) + (inv.amount || 0);
        }
      }

      const allMonths = new Set<string>();
      for (let m = 5; m >= 0; m--) {
        const d = new Date(now.getFullYear(), now.getMonth() - m, 1);
        allMonths.add(`${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`);
      }
      const sortedMonths = Array.from(allMonths).sort();

      const outcomeMargins = outcomes.map(o => {
        const costs = outcomeCostMap[o.id];
        const revenue = outcomeRevenueMap[o.id];

        const directCost = costs ? costs.llm + costs.tool : 0;
        const infraCost = directCost * INFRA_OVERHEAD_RATE;
        const totalCost = directCost + infraCost;
        const totalRevenue = revenue?.total || 0;
        const margin = totalRevenue - totalCost;
        const marginPercent = totalRevenue > 0 ? (margin / totalRevenue) * 100 : (totalCost > 0 ? -100 : 0);

        const trend = sortedMonths.map(month => {
          const mCost = costs?.monthly[month];
          const mDirectCost = mCost ? mCost.llm + mCost.tool : 0;
          const mInfraCost = mDirectCost * INFRA_OVERHEAD_RATE;
          const mTotalCost = mDirectCost + mInfraCost;
          const mRevenue = revenue?.monthly[month] || 0;
          const mMargin = mRevenue - mTotalCost;
          const mMarginPct = mRevenue > 0 ? (mMargin / mRevenue) * 100 : (mTotalCost > 0 ? -100 : 0);
          return {
            month,
            revenue: Math.round(mRevenue * 100) / 100,
            cost: Math.round(mTotalCost * 100) / 100,
            margin: Math.round(mMargin * 100) / 100,
            marginPercent: Math.round(mMarginPct * 10) / 10,
          };
        });

        const alerts: Array<{ type: string; severity: string; message: string }> = [];
        if (totalRevenue > 0 && marginPercent < 0) {
          alerts.push({ type: "negative_margin", severity: "critical", message: `Outcome "${o.name}" is operating at a loss (${marginPercent.toFixed(1)}% margin)` });
        } else if (totalRevenue > 0 && marginPercent < 20) {
          alerts.push({ type: "low_margin", severity: "warning", message: `Outcome "${o.name}" has thin margins (${marginPercent.toFixed(1)}%)` });
        }

        const recentTrend = trend.filter(t => t.revenue > 0 || t.cost > 0);
        if (recentTrend.length >= 2) {
          const prev = recentTrend[recentTrend.length - 2];
          const curr = recentTrend[recentTrend.length - 1];
          if (prev.marginPercent > 0 && curr.marginPercent < prev.marginPercent - 10) {
            alerts.push({ type: "margin_erosion", severity: "warning", message: `Margin dropped ${(prev.marginPercent - curr.marginPercent).toFixed(1)}% month-over-month` });
          }
        }

        const costBreakdown = {
          llmCost: Math.round((costs?.llm || 0) * 100) / 100,
          toolCost: Math.round((costs?.tool || 0) * 100) / 100,
          infraCost: Math.round(infraCost * 100) / 100,
        };

        return {
          outcomeId: o.id,
          outcomeName: o.name,
          revenue: Math.round(totalRevenue * 100) / 100,
          costToServe: Math.round(totalCost * 100) / 100,
          margin: Math.round(margin * 100) / 100,
          marginPercent: Math.round(marginPercent * 10) / 10,
          traceCount: costs?.traceCount || 0,
          costBreakdown,
          trend,
          alerts,
        };
      });

      const totalRevenue = outcomeMargins.reduce((s, o) => s + o.revenue, 0);
      const totalCost = outcomeMargins.reduce((s, o) => s + o.costToServe, 0);
      const overallMargin = totalRevenue - totalCost;
      const overallMarginPercent = totalRevenue > 0 ? (overallMargin / totalRevenue) * 100 : 0;

      const allAlerts = outcomeMargins.flatMap(o => o.alerts);

      const monthlyMargin = sortedMonths.map(month => {
        const mRevenue = outcomeMargins.reduce((s, o) => {
          const mt = o.trend.find(t => t.month === month);
          return s + (mt?.revenue || 0);
        }, 0);
        const mCost = outcomeMargins.reduce((s, o) => {
          const mt = o.trend.find(t => t.month === month);
          return s + (mt?.cost || 0);
        }, 0);
        return {
          month,
          revenue: Math.round(mRevenue * 100) / 100,
          cost: Math.round(mCost * 100) / 100,
          margin: Math.round((mRevenue - mCost) * 100) / 100,
          marginPercent: mRevenue > 0 ? Math.round(((mRevenue - mCost) / mRevenue) * 1000) / 10 : 0,
        };
      });

      res.json({
        summary: {
          totalRevenue: Math.round(totalRevenue * 100) / 100,
          totalCost: Math.round(totalCost * 100) / 100,
          overallMargin: Math.round(overallMargin * 100) / 100,
          overallMarginPercent: Math.round(overallMarginPercent * 10) / 10,
          outcomeCount: outcomes.length,
          alertCount: allAlerts.length,
        },
        outcomes: outcomeMargins.sort((a, b) => a.marginPercent - b.marginPercent),
        monthlyMargin,
        alerts: allAlerts,
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message || "Failed to compute margin analysis" });
    }
  });

  app.get("/api/billing/margin-alerts", async (req, res) => {
    try {
      const period = (req.query.period as string) || "90d";
      const now = new Date();
      let cutoff: Date | null = null;
      if (period === "30d") cutoff = new Date(now.getTime() - 30 * 86400000);
      else if (period === "90d") cutoff = new Date(now.getTime() - 90 * 86400000);

      const agents = await storage.getAgents();
      const outcomes = await storage.getOutcomes();
      const rawTraces = await storage.getTraces();
      const allTraces = cutoff ? rawTraces.filter(t => t.startedAt && new Date(t.startedAt) >= cutoff!) : rawTraces;
      const allInvoices = await storage.getInvoices();
      const agentMap = new Map(agents.map(a => [a.id, a]));

      const INFRA_OVERHEAD_RATE = 0.15;
      const TOOL_CALL_COST = 0.001;

      const alerts: Array<{
        outcomeId: string; outcomeName: string; type: string; severity: string; message: string;
        currentMargin: number; recommendedAction: string;
      }> = [];

      for (const outcome of outcomes) {
        const outcomeAgents = agents.filter(a => a.outcomeId === outcome.id);
        const agentIds = new Set(outcomeAgents.map(a => a.id));

        const outcomeTraces = allTraces.filter(t => agentIds.has(t.agentId));
        let totalCost = 0;
        for (const t of outcomeTraces) {
          const llm = t.costUsd || 0;
          const toolCalls = t.toolCalls as any[] | null;
          const tool = (Array.isArray(toolCalls) ? toolCalls.length : 0) * TOOL_CALL_COST;
          totalCost += (llm + tool) * (1 + INFRA_OVERHEAD_RATE);
        }

        const outcomeInvoices = allInvoices.filter(inv => inv.outcomeId === outcome.id);
        const totalRevenue = outcomeInvoices.reduce((s, inv) => s + (inv.amount || 0), 0);

        const margin = totalRevenue - totalCost;
        const marginPct = totalRevenue > 0 ? (margin / totalRevenue) * 100 : (totalCost > 0 ? -100 : 0);

        if (totalRevenue > 0 && marginPct < 0) {
          alerts.push({
            outcomeId: outcome.id, outcomeName: outcome.name,
            type: "negative_margin", severity: "critical",
            message: `Operating at a loss: ${marginPct.toFixed(1)}% margin ($${Math.abs(margin).toFixed(2)} loss)`,
            currentMargin: Math.round(marginPct * 10) / 10,
            recommendedAction: "Immediate review required: consider model downgrade, prompt compression, or price increase",
          });
        } else if (totalRevenue > 0 && marginPct < 20) {
          alerts.push({
            outcomeId: outcome.id, outcomeName: outcome.name,
            type: "low_margin", severity: "warning",
            message: `Thin margins at ${marginPct.toFixed(1)}%`,
            currentMargin: Math.round(marginPct * 10) / 10,
            recommendedAction: "Consider cost optimization patches: model downgrade for low-complexity tasks, token budget reduction",
          });
        }

        if (totalCost > 0 && totalRevenue === 0) {
          alerts.push({
            outcomeId: outcome.id, outcomeName: outcome.name,
            type: "no_revenue", severity: "warning",
            message: `$${totalCost.toFixed(2)} in costs with no invoiced revenue`,
            currentMargin: -100,
            recommendedAction: "Review billing configuration: ensure outcome events are being generated and invoiced",
          });
        }
      }

      res.json({
        alerts: alerts.sort((a, b) => {
          const sevOrder: Record<string, number> = { critical: 0, warning: 1, info: 2 };
          return (sevOrder[a.severity] || 2) - (sevOrder[b.severity] || 2);
        }),
        totalAlerts: alerts.length,
        criticalCount: alerts.filter(a => a.severity === "critical").length,
        warningCount: alerts.filter(a => a.severity === "warning").length,
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message || "Failed to compute margin alerts" });
    }
  });

  app.get("/api/billing/disputes", async (_req, res) => {
    const disputes = await storage.getBillingDisputes();
    res.json(disputes);
  });

  app.post("/api/billing/disputes", checkPermission("billing_invoices"), async (req, res) => {
    try {
      const data = insertBillingDisputeSchema.parse(req.body);
      const dispute = await storage.createBillingDispute(data);
      res.status(201).json(dispute);
    } catch (e) {
      handleZodError(res, e);
    }
  });

  app.patch("/api/billing/disputes/:id", checkPermission("billing_invoices"), async (req, res) => {
    const id = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;
    const updated = await storage.updateBillingDispute(id, req.body);
    if (!updated) return res.status(404).json({ error: "Dispute not found" });

    if ((updated.status === "resolved" || updated.status === "upheld") && updated.outcomeId) {
      try {
        const outcomeId = updated.outcomeId;
        const agents = (await storage.getAgents()).filter(a => a.outcomeId === outcomeId);
        if (agents.length > 0) {
          const primaryAgent = agents[0];
          const existingSuites = await storage.getEvalsByAgent(primaryAgent.id);
          const kpiSuite = existingSuites.find(s => s.type === "kpi_aligned");
          if (kpiSuite) {
            const existingCases = await storage.getEvalTestCases(kpiSuite.id);
            const alreadyExists = existingCases.some(tc => {
              const input = tc.inputData as Record<string, unknown> | null;
              return input?.sourceDisputeId === updated.id;
            });
            if (!alreadyExists) {
              let linkedEvent = null;
              if (updated.outcomeEventId) {
                linkedEvent = await storage.getOutcomeEvent(updated.outcomeEventId);
              }
              await storage.createEvalTestCase({
                suiteId: kpiSuite.id,
                name: `Auto-Synced Dispute: ${updated.category} - ${updated.reason.substring(0, 60)}`,
                inputData: {
                  type: "production_feedback",
                  sourceDisputeId: updated.id,
                  outcomeEventId: updated.outcomeEventId,
                  invoiceId: updated.invoiceId,
                  traceId: linkedEvent?.traceId,
                  agentId: linkedEvent?.agentId,
                  payload: linkedEvent?.payload,
                  disputeCategory: updated.category,
                  scenario: "billing_dispute",
                  autoSynced: true,
                },
                expectedOutput: {
                  shouldPass: false,
                  disputeReason: updated.reason,
                  disputeCategory: updated.category,
                  disputeResolution: updated.resolution,
                  expectedBehavior: `Agent output led to billing dispute (${updated.category}): ${updated.reason}. Future runs must avoid this failure.`,
                },
                tags: ["production_feedback", "ground_truth", "billing_dispute", "auto_synced", updated.category],
                weight: 2.0,
                origin: "production_feedback",
                severity: "critical",
              });
              const allCases = await storage.getEvalTestCases(kpiSuite.id);
              await storage.updateEvalSuite(kpiSuite.id, { totalCases: allCases.length });
            }
          }
        }
      } catch (_autoSyncErr) {
      }
    }

    res.json(updated);
  });

  app.get("/api/billing/usage-export", async (_req, res) => {
    try {
      const allEvents = await storage.getOutcomeEvents();
      const agents = await storage.getAgents();
      const outcomes = await storage.getOutcomes();

      const csvHeader = "Event ID,Outcome,Agent,Type,Billable,Exclude Reason,Unit Count,Unit Value,Trace ID,Created At\n";
      const csvRows = allEvents.map(e => {
        const outcome = outcomes.find(o => o.id === e.outcomeId);
        const agent = e.agentId ? agents.find(a => a.id === e.agentId) : null;
        return [
          e.id,
          `"${outcome?.name || e.outcomeId}"`,
          `"${agent?.name || e.agentId || ""}"`,
          e.type,
          e.billable ? "Yes" : "No",
          `"${e.excludeReason || ""}"`,
          e.unitCount || 1,
          e.unitValue || "",
          e.traceId || "",
          e.createdAt ? new Date(e.createdAt).toISOString() : "",
        ].join(",");
      }).join("\n");

      res.setHeader("Content-Type", "text/csv");
      res.setHeader("Content-Disposition", `attachment; filename=usage-export-${new Date().toISOString().split("T")[0]}.csv`);
      res.send(csvHeader + csvRows);
    } catch (e: any) {
      res.status(500).json({ error: e.message || "Export failed" });
    }
  });

  // ========== BILLING METERING PIPELINE ==========

  // Step 1: Runtime emits outcome candidate event
  // Applies exclusion rules, deduplication, fraud checks, signed hash
  app.post("/api/outcome-events", checkPermission("billing_invoices"), async (req, res) => {
    try {
      const eventSchema = z.object({
        outcomeId: z.string().min(1, "outcomeId is required"),
        agentId: z.string().optional().nullable(),
        traceId: z.string().optional().nullable(),
        type: z.string().min(1, "type is required"),
        payload: z.any().optional().nullable(),
        unitCount: z.number().int().positive().optional().default(1),
        unitValue: z.number().optional().nullable(),
      });
      const parsed = eventSchema.parse(req.body);
      const { outcomeId, agentId, traceId, type, payload, unitCount, unitValue } = parsed;

      const outcome = await storage.getOutcome(outcomeId);
      if (!outcome) {
        return res.status(404).json({ error: "Outcome not found" });
      }

      let billable = true;
      let excludeReason: string | null = null;
      const checks: string[] = [];

      // --- Exclusion rules ---
      if (outcome.status !== "active") {
        billable = false;
        excludeReason = "outcome_inactive";
        checks.push("EXCLUDED: outcome is not active");
      }

      if (billable && outcome.volumeCap) {
        const existingEvents = await storage.getOutcomeEventsByOutcome(outcomeId);
        const billableCount = existingEvents.filter(e => e.billable).length;
        if (billableCount >= outcome.volumeCap) {
          billable = false;
          excludeReason = "volume_cap_exceeded";
          checks.push(`EXCLUDED: volume cap ${outcome.volumeCap} reached (current: ${billableCount})`);
        }
      }

      // --- Deduplication: same traceId + outcomeId within 5-minute window ---
      if (billable && traceId) {
        const existingEvents = await storage.getOutcomeEventsByOutcome(outcomeId);
        const fiveMinAgo = new Date(Date.now() - 5 * 60 * 1000);
        const duplicate = existingEvents.find(e =>
          e.traceId === traceId &&
          e.createdAt && new Date(e.createdAt) > fiveMinAgo
        );
        if (duplicate) {
          billable = false;
          excludeReason = "duplicate_event";
          checks.push(`EXCLUDED: duplicate trace ${traceId} within 5-minute window (existing event: ${duplicate.id})`);
        }
      }

      // --- Fraud checks: volume spike detection ---
      if (billable) {
        const existingEvents = await storage.getOutcomeEventsByOutcome(outcomeId);
        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
        const recentCount = existingEvents.filter(e =>
          e.createdAt && new Date(e.createdAt) > oneHourAgo
        ).length;
        const avgHourlyRate = existingEvents.length > 0
          ? existingEvents.length / Math.max(1, (Date.now() - new Date(existingEvents[existingEvents.length - 1]?.createdAt || Date.now()).getTime()) / (60 * 60 * 1000))
          : 0;
        if (avgHourlyRate > 0 && recentCount > avgHourlyRate * 5) {
          billable = false;
          excludeReason = "fraud_volume_spike";
          checks.push(`EXCLUDED: volume spike detected (${recentCount} events in last hour vs avg ${Math.round(avgHourlyRate)}/hr)`);
        }
      }

      // --- Value anomaly check ---
      if (billable && unitValue !== undefined && unitValue !== null) {
        const existingEvents = await storage.getOutcomeEventsByOutcome(outcomeId);
        const billableValues = existingEvents
          .filter(e => e.billable && e.unitValue !== null && e.unitValue !== undefined)
          .map(e => e.unitValue as number);
        if (billableValues.length >= 5) {
          const mean = billableValues.reduce((s, v) => s + v, 0) / billableValues.length;
          const stdDev = Math.sqrt(billableValues.reduce((s, v) => s + (v - mean) ** 2, 0) / billableValues.length);
          if (stdDev > 0 && Math.abs(unitValue - mean) > 3 * stdDev) {
            billable = false;
            excludeReason = "fraud_value_anomaly";
            checks.push(`EXCLUDED: value anomaly (${unitValue} is >3 std devs from mean ${mean.toFixed(2)})`);
          }
        }
      }

      // --- Compute signed hash for tamper evidence ---
      const crypto = await import("crypto");
      const hashPayload = JSON.stringify({
        outcomeId, agentId, traceId, type, unitCount, unitValue,
        billable, excludeReason, timestamp: new Date().toISOString(),
      });
      const signedHash = crypto.createHash("sha256").update(hashPayload).digest("hex");

      const event = await storage.createOutcomeEvent({
        outcomeId,
        agentId: agentId || null,
        traceId: traceId || null,
        type,
        billable,
        excludeReason,
        unitCount: unitCount || 1,
        unitValue: unitValue || (outcome.pricePerUnit || 0),
        signedHash,
        payload: payload || null,
      });

      await storage.createAuditEvent({
        action: "outcome_event_ingested",
        objectType: "outcome_event",
        objectId: event.id,
        actorId: "metering_service",
        actorType: "system",
        details: `Event ${event.id} for outcome "${outcome.name}": billable=${billable}${excludeReason ? `, reason=${excludeReason}` : ""}. Checks: ${checks.length > 0 ? checks.join("; ") : "all passed"}`,
      });

      let flywheelAutoSync: any = null;
      if (!billable && excludeReason) {
        try {
          const agents = (await storage.getAgents()).filter(a => a.outcomeId === outcomeId);
          if (agents.length > 0) {
            const primaryAgent = agents[0];
            const existingSuites = await storage.getEvalsByAgent(primaryAgent.id);
            let kpiSuite = existingSuites.find(s => s.type === "kpi_aligned");
            if (!kpiSuite) {
              const generated = await generateKpiAlignedEvalSuite(primaryAgent.id, outcomeId);
              if (generated) {
                kpiSuite = generated.suite;
              } else {
                kpiSuite = await storage.createEvalSuite({
                  agentId: primaryAgent.id,
                  name: `${primaryAgent.name} - Production Feedback Suite (${outcome.name})`,
                  type: "kpi_aligned",
                  totalCases: 0,
                  coverageTags: ["production_feedback", "ground_truth"],
                  ontologyTags: { kpiAligned: true, outcomeId, outcomeName: outcome.name, generatedAt: new Date().toISOString() },
                });
              }
            }

            const suiteId = kpiSuite!.id;
            const existingCases = await storage.getEvalTestCases(suiteId);
            const alreadyExists = existingCases.some(tc => {
              const input = tc.inputData as Record<string, unknown> | null;
              return input?.sourceEventId === event.id;
            });

            if (!alreadyExists) {
              const tc = await storage.createEvalTestCase({
                suiteId,
                name: `Production Rejection: ${excludeReason} (${type})`,
                inputData: {
                  type: "production_feedback",
                  sourceEventId: event.id,
                  traceId: traceId || null,
                  agentId: agentId || null,
                  eventType: type,
                  payload: payload || null,
                  scenario: "rejected_outcome_event",
                  groundTruthLabel: "negative",
                  autoSynced: true,
                  trigger: "event_rejection",
                },
                expectedOutput: {
                  shouldPass: false,
                  rejectionReason: excludeReason,
                  expectedBehavior: `Agent output was rejected: ${excludeReason}. Future runs must not reproduce this failure pattern.`,
                },
                tags: ["production_feedback", "ground_truth", "rejected_event", "auto_synced", excludeReason],
                weight: 1.5,
                origin: "production_feedback",
                severity: "high",
              });

              const currentCases = await storage.getEvalTestCases(suiteId);
              await storage.updateEvalSuite(suiteId, { totalCases: currentCases.length });

              flywheelAutoSync = { suiteId, testCaseId: tc.id, trigger: "event_rejection" };

              await storage.createAuditEvent({
                actorType: "system",
                action: "flywheel_auto_sync",
                objectType: "eval_test_case",
                objectId: tc.id,
                details: `Auto-created negative ground truth test case from rejected event ${event.id} (reason: ${excludeReason}) for outcome ${outcome.name}`,
              });
            }
          }
        } catch (syncErr: any) {
          flywheelAutoSync = { error: syncErr.message };
        }
      }

      let autonomyValidation: any = null;
      if (agentId) {
        try {
          const pendingDecisions = await storage.getAutonomyDecisions({ agentId, outcome: "pending" });
          const thirtyMinAgo = new Date(Date.now() - 30 * 60 * 1000);
          const recentPending = pendingDecisions.filter((d: any) => d.createdAt && new Date(d.createdAt) >= thirtyMinAgo);
          let validatedCount = 0;
          for (const dec of recentPending) {
            const outcome_val = billable ? "validated_correct" : "validated_incorrect";
            await storage.updateAutonomyDecision(dec.id, {
              outcome: outcome_val,
              outcomeSource: "customer_acceptance",
              outcomeDetails: { eventId: event.id, billable, excludeReason: excludeReason || null } as any,
              outcomeAt: new Date(),
            });
            const profiles = await storage.getDecisionQualityProfiles({ agentId: dec.agentId, decisionType: dec.decisionType });
            const matching = profiles.find((p: any) => (p.riskDimension || null) === (dec.riskDimension || null));
            if (matching) {
              const newCorrect = matching.correctDecisions + (billable ? 1 : 0);
              const newIncorrect = matching.incorrectDecisions + (billable ? 0 : 1);
              const newPending = Math.max(0, matching.pendingDecisions - 1);
              const resolved = newCorrect + newIncorrect;
              await storage.updateDecisionQualityProfile(matching.id, {
                correctDecisions: newCorrect,
                incorrectDecisions: newIncorrect,
                pendingDecisions: newPending,
                accuracyRate: resolved > 0 ? Math.round((newCorrect / resolved) * 10000) / 10000 : 0,
                updatedAt: new Date(),
              });
            }
            validatedCount++;
          }
          if (validatedCount > 0) {
            autonomyValidation = { validatedDecisions: validatedCount, outcomeSignal: billable ? "correct" : "incorrect" };
          }
        } catch (_autoValErr) {}
      }

      res.status(201).json({
        event,
        metering: { billable, excludeReason, checks, signedHash },
        flywheelAutoSync,
        autonomyValidation,
      });
    } catch (e: any) {
      if (e.name === "ZodError") {
        return res.status(400).json({ error: "Validation failed", details: e.errors });
      }
      res.status(500).json({ error: e.message || "Failed to ingest outcome event" });
    }
  });

  // GET all outcome events
  app.get("/api/outcome-events", async (_req, res) => {
    const events = await storage.getOutcomeEvents();
    res.json(events);
  });

  // GET single outcome event
  app.get("/api/outcome-events/:id", async (req, res) => {
    const event = await storage.getOutcomeEvent(req.params.id);
    if (!event) return res.status(404).json({ error: "Outcome event not found" });
    res.json(event);
  });

  // GET outcome event -> trace drill-down
  app.get("/api/outcome-events/:id/trace", async (req, res) => {
    const event = await storage.getOutcomeEvent(req.params.id);
    if (!event) return res.status(404).json({ error: "Outcome event not found" });
    if (!event.traceId) return res.status(404).json({ error: "No trace linked to this event" });
    const trace = await storage.getTrace(event.traceId);
    if (!trace) return res.status(404).json({ error: "Linked trace not found" });
    const outcome = await storage.getOutcome(event.outcomeId);
    const agent = event.agentId ? await storage.getAgent(event.agentId) : null;
    res.json({
      event,
      trace,
      outcome: outcome ? { id: outcome.id, name: outcome.name, pricingModel: outcome.pricingModel } : null,
      agent: agent ? { id: agent.id, name: agent.name } : null,
    });
  });

  app.get("/api/flywheel/metrics", async (_req, res) => {
    try {
      const [allSuites, allOutcomes, allAgents, allEvents, allGoldenDatasets, allEvalRuns] = await Promise.all([
        storage.getEvalSuites(),
        storage.getOutcomes(),
        storage.getAgents(),
        storage.getOutcomeEvents(),
        storage.getGoldenDatasets(),
        storage.getAllEvalRuns(),
      ]);

      const allTestCases: Array<{ suiteId: string; tags: string[] | null; origin: string | null; lastRunAt: Date | null }> = [];
      for (const suite of allSuites) {
        const cases = await storage.getEvalTestCases(suite.id);
        for (const tc of cases) {
          allTestCases.push({
            suiteId: suite.id,
            tags: tc.tags,
            origin: tc.origin,
            lastRunAt: suite.lastRunAt,
          });
        }
      }

      const productionFeedbackCases = allTestCases.filter(tc => tc.origin === "production_feedback");
      let positiveLabels = 0;
      let negativeLabels = 0;
      for (const tc of productionFeedbackCases) {
        const tags = (tc.tags || []).map(t => t.toLowerCase());
        if (tags.includes("rejected_event") || tags.includes("billing_dispute")) {
          negativeLabels++;
        } else if (tags.includes("accepted_event")) {
          positiveLabels++;
        } else {
          positiveLabels++;
        }
      }
      const totalGroundTruth = productionFeedbackCases.length;

      const monthlyMap = new Map<string, { positive: number; negative: number; total: number }>();
      for (const tc of productionFeedbackCases) {
        const date = tc.lastRunAt ? new Date(tc.lastRunAt) : new Date();
        const month = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
        if (!monthlyMap.has(month)) monthlyMap.set(month, { positive: 0, negative: 0, total: 0 });
        const entry = monthlyMap.get(month)!;
        const tags = (tc.tags || []).map(t => t.toLowerCase());
        if (tags.includes("rejected_event") || tags.includes("billing_dispute")) {
          entry.negative++;
        } else {
          entry.positive++;
        }
        entry.total++;
      }
      const monthlyGrowth = Array.from(monthlyMap.entries())
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([month, data]) => ({ month, ...data }));

      const eventsByMonth = new Map<string, { totalEvents: number; accepted: number }>();
      for (const ev of allEvents) {
        const date = ev.createdAt ? new Date(ev.createdAt) : new Date();
        const month = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
        if (!eventsByMonth.has(month)) eventsByMonth.set(month, { totalEvents: 0, accepted: 0 });
        const entry = eventsByMonth.get(month)!;
        entry.totalEvents++;
        if (ev.billable) entry.accepted++;
      }
      const acceptanceTrend = Array.from(eventsByMonth.entries())
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([month, data]) => ({
          month,
          rate: data.totalEvents > 0 ? Math.round((data.accepted / data.totalEvents) * 10000) / 100 : 0,
          totalEvents: data.totalEvents,
          accepted: data.accepted,
        }));

      let goldenPromotions = 0;
      for (const ds of allGoldenDatasets) {
        const goldenCases = await storage.getGoldenTestCases(ds.id);
        goldenPromotions += goldenCases.filter(gc => gc.contributorOrg === "production_feedback").length;
      }

      const totalAccepted = allEvents.filter(e => e.billable).length;
      const overallAcceptanceRate = allEvents.length > 0
        ? Math.round((totalAccepted / allEvents.length) * 10000) / 100
        : 0;

      const agentsByOutcome = new Map<string, string[]>();
      for (const agent of allAgents) {
        if (agent.outcomeId) {
          if (!agentsByOutcome.has(agent.outcomeId)) agentsByOutcome.set(agent.outcomeId, []);
          agentsByOutcome.get(agent.outcomeId)!.push(agent.id);
        }
      }

      const suitesByAgent = new Map<string, string[]>();
      for (const suite of allSuites) {
        if (!suitesByAgent.has(suite.agentId)) suitesByAgent.set(suite.agentId, []);
        suitesByAgent.get(suite.agentId)!.push(suite.id);
      }

      const latestRunBySuite = new Map<string, { passRate: number | null; startedAt: Date | null }>();
      for (const run of allEvalRuns) {
        const existing = latestRunBySuite.get(run.suiteId);
        const runDate = run.startedAt ? new Date(run.startedAt) : null;
        if (!existing || (runDate && (!existing.startedAt || runDate > existing.startedAt))) {
          latestRunBySuite.set(run.suiteId, { passRate: run.passRate, startedAt: runDate });
        }
      }

      const productionCasesBySuite = new Map<string, number>();
      for (const tc of productionFeedbackCases) {
        productionCasesBySuite.set(tc.suiteId, (productionCasesBySuite.get(tc.suiteId) || 0) + 1);
      }

      const outcomeStatus = allOutcomes.map(outcome => {
        const agentIds = agentsByOutcome.get(outcome.id) || [];
        const outcomeEvents = allEvents.filter(e => e.outcomeId === outcome.id);
        const acceptedEvents = outcomeEvents.filter(e => e.billable).length;
        const acceptanceRate = outcomeEvents.length > 0
          ? Math.round((acceptedEvents / outcomeEvents.length) * 10000) / 100
          : 0;

        let groundTruthCases = 0;
        const passRates: number[] = [];
        for (const agentId of agentIds) {
          const suiteIds = suitesByAgent.get(agentId) || [];
          for (const suiteId of suiteIds) {
            groundTruthCases += productionCasesBySuite.get(suiteId) || 0;
            const latestRun = latestRunBySuite.get(suiteId);
            if (latestRun && latestRun.passRate != null) {
              passRates.push(latestRun.passRate);
            }
          }
        }

        const evalPassRate = passRates.length > 0
          ? Math.round((passRates.reduce((a, b) => a + b, 0) / passRates.length) * 100) / 100
          : 0;

        return {
          outcomeId: outcome.id,
          outcomeName: outcome.name,
          groundTruthCases,
          acceptanceRate,
          evalPassRate,
        };
      });

      res.json({
        summary: {
          totalGroundTruth,
          positiveLabels,
          negativeLabels,
          goldenPromotions,
          acceptanceRate: overallAcceptanceRate,
        },
        monthlyGrowth,
        acceptanceTrend,
        outcomeStatus,
      });
    } catch (error: any) {
      console.error("Error computing flywheel metrics:", error);
      res.status(500).json({ error: "Failed to compute flywheel metrics" });
    }
  });

  app.get("/api/flywheel/acceptance-patterns", async (_req, res) => {
    try {
      const [allEvents, allAgents, allDisputes] = await Promise.all([
        storage.getOutcomeEvents(),
        storage.getAgents(),
        storage.getBillingDisputes(),
      ]);

      const agentIndustryMap = new Map<string, string>();
      for (const agent of allAgents) {
        let industry = "general";
        const tags: string[] = [];
        if (Array.isArray(agent.complianceTags)) tags.push(...agent.complianceTags);
        if (Array.isArray(agent.ontologyTags)) {
          for (const t of agent.ontologyTags as any[]) {
            if (typeof t === "string") tags.push(t);
            else if (t && typeof t === "object" && t.conceptLabel) tags.push(t.conceptLabel);
            else if (t && typeof t === "object" && t.conceptId) tags.push(t.conceptId);
          }
        }
        const combined = tags.join(" ").toUpperCase();
        if (combined.includes("HIPAA") || combined.includes("HITECH")) industry = "healthcare";
        else if (combined.includes("BSA") || combined.includes("AML") || combined.includes("SOX") || combined.includes("CIP") || combined.includes("GLBA")) industry = "financial_services";
        else if (combined.includes("NAIC")) industry = "insurance";
        else if (combined.includes("OSHA") || combined.includes("ISO 9001")) industry = "manufacturing";
        else if (combined.includes("PCI-DSS") || combined.includes("PCI") || combined.includes("CCPA") || combined.includes("FTC")) industry = "retail";
        else if (combined.includes("SOC 2") || combined.includes("FEDRAMP") || combined.includes("ISO 27001")) industry = "technology_saas";
        if (agent.department) {
          const dept = agent.department.toLowerCase();
          if (dept.includes("health") || dept.includes("clinical")) industry = "healthcare";
          else if (dept.includes("financ") || dept.includes("bank")) industry = "financial_services";
          else if (dept.includes("insurance") || dept.includes("underwriting")) industry = "insurance";
          else if (dept.includes("manufactur") || dept.includes("production")) industry = "manufacturing";
          else if (dept.includes("retail") || dept.includes("commerce")) industry = "retail";
          else if (dept.includes("tech") || dept.includes("saas") || dept.includes("engineering")) industry = "technology_saas";
        }
        agentIndustryMap.set(agent.id, industry);
      }

      const eventsByIndustry = new Map<string, typeof allEvents>();
      for (const ev of allEvents) {
        const industry = (ev.agentId && agentIndustryMap.get(ev.agentId)) || "general";
        if (!eventsByIndustry.has(industry)) eventsByIndustry.set(industry, []);
        eventsByIndustry.get(industry)!.push(ev);
      }

      const disputesByOutcome = new Map<string, typeof allDisputes>();
      for (const d of allDisputes) {
        const oid = d.outcomeId || "";
        if (!disputesByOutcome.has(oid)) disputesByOutcome.set(oid, []);
        disputesByOutcome.get(oid)!.push(d);
      }

      const outcomeToIndustry = new Map<string, string>();
      for (const agent of allAgents) {
        if (agent.outcomeId) {
          outcomeToIndustry.set(agent.outcomeId, agentIndustryMap.get(agent.id) || "general");
        }
      }

      const overallTotal = allEvents.length;
      const overallAccepted = allEvents.filter(e => e.billable === true).length;
      const overallAcceptanceRate = overallTotal > 0 ? Math.round((overallAccepted / overallTotal) * 10000) / 100 : 0;

      const overallRejectionReasons = new Map<string, number>();
      for (const ev of allEvents) {
        if (!ev.billable && ev.excludeReason) {
          overallRejectionReasons.set(ev.excludeReason, (overallRejectionReasons.get(ev.excludeReason) || 0) + 1);
        }
      }
      const overallRejectionTotal = Array.from(overallRejectionReasons.values()).reduce((s, c) => s + c, 0);

      const industries: any[] = [];

      for (const [industry, events] of eventsByIndustry.entries()) {
        const totalEvents = events.length;
        const accepted = events.filter(e => e.billable === true).length;
        const acceptanceRate = totalEvents > 0 ? Math.round((accepted / totalEvents) * 10000) / 100 : 0;

        const rejectionReasons = new Map<string, number>();
        for (const ev of events) {
          if (!ev.billable && ev.excludeReason) {
            rejectionReasons.set(ev.excludeReason, (rejectionReasons.get(ev.excludeReason) || 0) + 1);
          }
        }
        const totalRejections = Array.from(rejectionReasons.values()).reduce((s, c) => s + c, 0);
        const topRejectionReasons = Array.from(rejectionReasons.entries())
          .sort((a, b) => b[1] - a[1])
          .slice(0, 10)
          .map(([reason, count]) => ({ reason, count, percentOfRejections: totalRejections > 0 ? Math.round((count / totalRejections) * 1000) / 10 : 0 }));

        const industryOutcomeIds = new Set<string>();
        for (const ev of events) {
          if (ev.outcomeId) industryOutcomeIds.add(ev.outcomeId);
        }
        const disputeCategories = new Map<string, number>();
        for (const oid of industryOutcomeIds) {
          const disputes = disputesByOutcome.get(oid) || [];
          for (const d of disputes) {
            disputeCategories.set(d.category, (disputeCategories.get(d.category) || 0) + 1);
          }
        }
        const topDisputeCategories = Array.from(disputeCategories.entries())
          .sort((a, b) => b[1] - a[1])
          .slice(0, 10)
          .map(([category, count]) => ({ category, count }));

        const monthlyBuckets = new Map<string, { total: number; accepted: number }>();
        for (const ev of events) {
          if (!ev.createdAt) continue;
          const d = new Date(ev.createdAt);
          const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
          if (!monthlyBuckets.has(key)) monthlyBuckets.set(key, { total: 0, accepted: 0 });
          const bucket = monthlyBuckets.get(key)!;
          bucket.total++;
          if (ev.billable === true) bucket.accepted++;
        }
        const monthlyTrend = Array.from(monthlyBuckets.entries())
          .sort((a, b) => a[0].localeCompare(b[0]))
          .map(([month, data]) => ({
            month,
            totalEvents: data.total,
            acceptedEvents: data.accepted,
            acceptanceRate: data.total > 0 ? Math.round((data.accepted / data.total) * 10000) / 100 : 0,
          }));

        const industryRejectionTotal = Array.from(rejectionReasons.values()).reduce((s, c) => s + c, 0);
        const distinctiveFailureModes: any[] = [];
        if (overallRejectionTotal > 0 && industryRejectionTotal > 0) {
          for (const [reason, count] of rejectionReasons.entries()) {
            const industryRate = count / industryRejectionTotal;
            const overallCount = overallRejectionReasons.get(reason) || 0;
            const overallRate = overallCount / overallRejectionTotal;
            if (overallRate > 0) {
              const overRepresentationFactor = Math.round((industryRate / overallRate) * 100) / 100;
              if (overRepresentationFactor > 1.5) {
                distinctiveFailureModes.push({
                  reason,
                  industryCount: count,
                  industryRate: Math.round(industryRate * 10000) / 100,
                  overallRate: Math.round(overallRate * 10000) / 100,
                  overRepresentationFactor,
                });
              }
            }
          }
          distinctiveFailureModes.sort((a, b) => b.overRepresentationFactor - a.overRepresentationFactor);
        }

        industries.push({
          industry,
          acceptanceRate,
          totalEvents,
          acceptedEvents: accepted,
          rejectedEvents: totalEvents - accepted,
          topRejectionReasons,
          topDisputeCategories,
          monthlyTrend,
          distinctiveFailureModes,
        });
      }

      industries.sort((a, b) => b.totalEvents - a.totalEvents);

      res.json({
        industries,
        overallAcceptanceRate,
        totalEvents: overallTotal,
        totalAccepted: overallAccepted,
        totalRejected: overallTotal - overallAccepted,
        industriesCount: industries.length,
      });
    } catch (error: any) {
      console.error("Acceptance patterns error:", error);
      res.status(500).json({ error: "Failed to compute acceptance patterns", details: error.message });
    }
  });

  // Step 4-5: Billing aggregates events for period, creates invoice + line items
  app.post("/api/billing/generate-invoice", checkPermission("billing_invoices"), async (req, res) => {
    try {
      const { outcomeId, periodStart, periodEnd } = req.body;
      if (!outcomeId) {
        return res.status(400).json({ error: "outcomeId is required" });
      }

      const outcome = await storage.getOutcome(outcomeId);
      if (!outcome) {
        return res.status(404).json({ error: "Outcome not found" });
      }

      const pStart = periodStart ? new Date(periodStart) : new Date(new Date().getFullYear(), new Date().getMonth(), 1);
      const pEnd = periodEnd ? new Date(periodEnd) : new Date();

      // Get all billable events for this outcome in the period that are not yet invoiced
      const allEvents = await storage.getOutcomeEventsByOutcome(outcomeId);
      const eligibleEvents = allEvents.filter(e => {
        if (!e.billable) return false;
        if (e.invoiceId) return false;
        if (!e.createdAt) return false;
        const eventDate = new Date(e.createdAt);
        return eventDate >= pStart && eventDate <= pEnd;
      });

      if (eligibleEvents.length === 0) {
        return res.status(400).json({ error: "No unbilled billable events found for this period" });
      }

      // Compute totals based on pricing model
      let totalAmount = 0;
      const totalUnits = eligibleEvents.reduce((sum, e) => sum + (e.unitCount || 1), 0);
      const pricingModel = outcome.pricingModel || "PER_OUTCOME_EVENT";

      if (pricingModel === "PER_OUTCOME_EVENT") {
        const pricePerUnit = outcome.pricePerUnit || 0;
        totalAmount = totalUnits * pricePerUnit;
      } else if (pricingModel === "TIERED") {
        const tiers = (outcome.pricingTiers as Array<{ upTo: number; price: number }>) || [];
        let remaining = totalUnits;
        let prevLimit = 0;
        for (const tier of tiers) {
          const tierUnits = Math.min(remaining, (tier.upTo || Infinity) - prevLimit);
          if (tierUnits <= 0) break;
          totalAmount += tierUnits * (tier.price || 0);
          remaining -= tierUnits;
          prevLimit = tier.upTo || Infinity;
        }
        if (remaining > 0 && tiers.length > 0) {
          totalAmount += remaining * (tiers[tiers.length - 1].price || 0);
        }
      } else if (pricingModel === "MONTHLY_FIXED") {
        totalAmount = outcome.pricePerUnit || 0;
      }

      // Create the invoice
      const invoice = await storage.createInvoice({
        outcomeId,
        outcomeName: outcome.name,
        periodStart: pStart,
        periodEnd: pEnd,
        totalUnits,
        billableUnits: totalUnits,
        excludedUnits: 0,
        unitPrice: outcome.pricePerUnit || 0,
        amount: Math.round(totalAmount * 100) / 100,
        status: "pending",
      });

      // Link all eligible events to this invoice
      let linkedCount = 0;
      for (const event of eligibleEvents) {
        try {
          await storage.updateOutcomeEvent(event.id, { invoiceId: invoice.id });
          linkedCount++;
        } catch (linkErr: any) {
          await storage.createAuditEvent({
            action: "invoice_event_link_failed",
            objectType: "outcome_event",
            objectId: event.id,
            actorId: "billing_service",
            actorType: "system",
            details: `Failed to link event ${event.id} to invoice ${invoice.id}: ${linkErr.message}`,
          });
        }
      }

      if (linkedCount < eligibleEvents.length) {
        await storage.updateInvoice(invoice.id, {
          billableUnits: linkedCount,
          totalUnits: linkedCount,
        });
      }

      // Audit event
      await storage.createAuditEvent({
        action: "invoice_generated",
        objectType: "invoice",
        objectId: invoice.id,
        actorId: "billing_service",
        actorType: "system",
        details: `Invoice ${invoice.id} generated for outcome "${outcome.name}": ${totalUnits} units, $${totalAmount.toFixed(2)} (${pricingModel}), period ${pStart.toISOString().split("T")[0]} to ${pEnd.toISOString().split("T")[0]}`,
      });

      // Notification audit event for finance users
      await storage.createAuditEvent({
        action: "invoice_ready_notification",
        objectType: "invoice",
        objectId: invoice.id,
        actorId: "billing_service",
        actorType: "system",
        details: `Invoice ready for review: $${totalAmount.toFixed(2)} for "${outcome.name}" (${eligibleEvents.length} events, ${totalUnits} units). Period: ${pStart.toISOString().split("T")[0]} to ${pEnd.toISOString().split("T")[0]}`,
      });

      res.status(201).json({
        invoice,
        summary: {
          pricingModel,
          eventsLinked: eligibleEvents.length,
          totalUnits,
          unitPrice: outcome.pricePerUnit || 0,
          totalAmount: Math.round(totalAmount * 100) / 100,
          periodStart: pStart.toISOString(),
          periodEnd: pEnd.toISOString(),
        },
      });
    } catch (e: any) {
      res.status(500).json({ error: e.message || "Failed to generate invoice" });
    }
  });

  // ========== END BILLING METERING PIPELINE ==========

  app.get("/api/outcome-risk-drivers", async (_req, res) => {
    try {
      const traces = await storage.getTraces();
      const agents = await storage.getAgents();
      const policies = await storage.getPolicies();

      const drivers: Array<{
        type: string;
        label: string;
        severity: string;
        detail: string;
      }> = [];

      const failedTraces = traces.filter((t) => t.status === "failed" || t.status === "error");
      if (failedTraces.length > 0) {
        const recentFails = failedTraces.slice(0, 5);
        const agentIds = Array.from(new Set(recentFails.map((t) => t.agentId)));
        const agentNames = agentIds
          .map((id) => agents.find((a) => a.id === id)?.name || "Unknown")
          .slice(0, 3);
        drivers.push({
          type: "tool_failure",
          label: `${failedTraces.length} failed run(s)`,
          severity: failedTraces.length >= 5 ? "critical" : failedTraces.length >= 2 ? "high" : "medium",
          detail: `Agents: ${agentNames.join(", ")}`,
        });
      }

      const toolCallFailures: string[] = [];
      for (const trace of traces.slice(0, 50)) {
        const calls = trace.toolCalls as Array<{ name?: string; status?: string }> | null;
        if (Array.isArray(calls)) {
          calls.forEach((c) => {
            if (c.status === "failed" || c.status === "error") {
              toolCallFailures.push(c.name || "unknown");
            }
          });
        }
      }
      if (toolCallFailures.length > 0) {
        const unique = Array.from(new Set(toolCallFailures)).slice(0, 3);
        drivers.push({
          type: "tool_failure",
          label: `${toolCallFailures.length} tool call failure(s)`,
          severity: toolCallFailures.length >= 5 ? "high" : "medium",
          detail: `Tools: ${unique.join(", ")}`,
        });
      }

      let policyViolationCount = 0;
      for (const trace of traces.slice(0, 50)) {
        const checks = trace.policyChecks as Array<{ result?: string; status?: string }> | null;
        if (Array.isArray(checks)) {
          checks.forEach((c) => {
            if (c.result === "violation" || c.status === "violated") {
              policyViolationCount++;
            }
          });
        }
      }
      if (policyViolationCount > 0) {
        drivers.push({
          type: "policy_violation",
          label: `${policyViolationCount} policy violation(s)`,
          severity: policyViolationCount >= 5 ? "critical" : policyViolationCount >= 2 ? "high" : "medium",
          detail: "Detected in recent run traces",
        });
      }

      const stalePolicies = policies.filter((p) => p.status === "draft" || p.status === "deprecated");
      if (stalePolicies.length > 0) {
        drivers.push({
          type: "policy_violation",
          label: `${stalePolicies.length} stale policy(ies)`,
          severity: "low",
          detail: stalePolicies.map((p) => p.name).slice(0, 3).join(", "),
        });
      }

      res.json(drivers);
    } catch (e) {
      res.status(500).json({ error: "Failed to compute risk drivers" });
    }
  });

  // Agent Templates
