          agentId: agent.id,
          changeType: sp.changeType,
          title: sp.title,
          description: sp.desc,
          diff: sampleDiffs[i] || { lines: [{ type: "context", content: "// no diff available" }] },
          expectedKpiImpact: sp.kpi,
          expectedCostImpact: sp.cost,
          riskLevel: sp.risk,
